import { useState, type FormEvent } from 'react';
import { useNavigate } from 'react-router-dom';
import RivvyLogo from '../components/RivvyLogo';
import { colors, fonts } from '../theme';

function LoginPage() {
  const navigate = useNavigate();
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [rememberMe, setRememberMe] = useState(false);
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      const response = await fetch('/api/auth/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'include',
        body: JSON.stringify({ email, password, rememberMe }),
      });

      if (response.ok) {
        const data = await response.json();
        navigate(data.redirectUrl);
      } else if (response.status === 401) {
        const data = await response.json();
        setError(data.error || 'Invalid email or password');
      } else {
        setError('An unexpected error occurred. Please try again.');
      }
    } catch {
      setError('Unable to connect. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div data-testid="page-login" style={styles.container}>
      <div style={styles.inner}>
        <div style={styles.logoSection}>
          <RivvyLogo size="large" />
        </div>
        <div style={styles.card}>
          <h1 style={styles.title}>Sign in</h1>
          <form onSubmit={handleSubmit}>
            <div style={styles.field}>
              <label htmlFor="email" style={styles.label}>Email</label>
              <input
                id="email"
                type="email"
                required
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                disabled={loading}
                style={styles.input}
              />
            </div>
            <div style={styles.field}>
              <label htmlFor="password" style={styles.label}>Password</label>
              <input
                id="password"
                type="password"
                required
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                disabled={loading}
                style={styles.input}
              />
            </div>
            <div style={styles.checkboxField}>
              <input
                id="rememberMe"
                type="checkbox"
                checked={rememberMe}
                onChange={(e) => setRememberMe(e.target.checked)}
                disabled={loading}
              />
              <label htmlFor="rememberMe" style={styles.checkboxLabel}>Remember me</label>
            </div>
            {error && (
              <div role="alert" style={styles.error}>{error}</div>
            )}
            <button
              type="submit"
              disabled={loading}
              style={{
                ...styles.button,
                ...(loading ? styles.buttonDisabled : {}),
              }}
            >
              {loading ? 'Signing in...' : 'Sign in'}
            </button>
          </form>
        </div>
      </div>
    </div>
  );
}

const styles: Record<string, React.CSSProperties> = {
  container: {
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
    minHeight: '100vh',
    padding: '2rem',
  },
  inner: {
    width: '100%',
    maxWidth: '400px',
  },
  logoSection: {
    marginBottom: '3rem',
  },
  card: {
    width: '100%',
    padding: '2.5rem',
    backgroundColor: colors.cream,
    borderRadius: '2px',
    border: `1px solid ${colors.borderCream}`,
  },
  title: {
    marginTop: 0,
    marginBottom: '2rem',
    fontSize: '1.5rem',
    fontFamily: fonts.heading,
    fontWeight: 400,
    textAlign: 'center' as const,
